import React, { useEffect, useState } from "react";
import axiosInstance from "../lib/instance";

function YourStores() {
  const [stores, setStores] = useState([]);
  const [loading, setLoading] = useState(false);

  // ✅ Fetch store owner's stores
  const fetchMyStores = async () => {
    setLoading(true);
    try {
      const res = await axiosInstance.get("/stores"); // adjust if needed

      console.log("My Stores:", res.data);

      if (res?.data?.data) {
        setStores(res.data.data);
      }
    } catch (error) {
      console.error("Fetch my stores error:", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchMyStores();
  }, []);

  return (
    <div>
      <h2 className="text-xl font-bold mb-4">Your Stores</h2>

      {loading ? (
        <p>Loading...</p>
      ) : stores.length > 0 ? (
        stores.map((store) => (
          <div
            key={store.id}
            className="bg-white p-4 rounded shadow mb-6"
          >
            {/* ✅ Store Info */}
            <div className="mb-4">
              <h3 className="text-lg font-semibold">{store.name}</h3>
              <p className="text-gray-600">{store.address}</p>

              <p className="mt-2 font-medium">
                ⭐ Avg Rating: {store.averageRating || 0}
              </p>

              <p className="text-sm text-gray-500">
                Total Ratings: {store.totalRatings || 0}
              </p>
            </div>

            {/* ✅ Users Who Rated */}
            <h4 className="font-semibold mb-2">
              Users who rated this store
            </h4>

            <table className="w-full text-center border">
              <thead className="bg-indigo-600 text-white">
                <tr>
                  <th>Name</th>
                  <th>Email</th>
                  <th>Rating</th>
                  <th>Rated At</th>
                </tr>
              </thead>

              <tbody>
                {store.usersWhoRated &&
                store.usersWhoRated.length > 0 ? (
                  store.usersWhoRated.map((u, index) => (
                    <tr key={index} className="border-b">
                      <td>{u.name}</td>
                      <td>{u.email}</td>
                      <td>⭐ {u.rating}</td>
                      <td>
                        {new Date(u.ratedAt).toLocaleString()}
                      </td>
                    </tr>
                  ))
                ) : (
                  <tr>
                    <td colSpan="4">No ratings yet</td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        ))
      ) : (
        <p>No stores found</p>
      )}
    </div>
  );
}

export default YourStores;
